        return False
    if not (10**14 < x < 10**15):
        return False

    def ok(n, a):
        if n % a == 0:
            return n == a

        d = n - 1
        s = 0
        while d % 2 == 0:
            s += 1
            d //= 2

        y = pow(a, d, n)
        if y == 1 or y == n - 1:
            return True

        for _ in range(s - 1):
            y = (y * y) % n
            if y == n - 1:
                return True

        return False

    if x % 10670053 != 0:
        return False

    return all(ok(x, a) for a in (2, 3, 5, 7, 11, 13, 17))

