    D = 73
    diff = x * x - 1
    if diff % D != 0:
        return False
    y2 = diff // D
    y = int(round(y2 ** 0.5))
    # adjust for float imprecision
    while y > 0 and y * y > y2:
        y -= 1
    while (y + 1) * (y + 1) <= y2:
