def mystery(x):
    if type(x) is not str:
        return False

    n = 52
    if len(x) != 2 * n:
        return False
    if any(c < "0" or c > "9" for c in x):
        return False

    p = [int(x[i:i + 2]) for i in range(0, 2 * n, 2)]

    if sorted(p) != list(range(1, n + 1)):
        return False

    seen = set()
    for i, a in enumerate(p):
        for j in range(i + 1, n):
            d = (j - i, p[j] - a)
            if d in seen:
                return False
            seen.add(d)

    return True

